INSERT INTO `news` VALUES (7,2,'Capital Group и УЭЗ приступили к строительству жилого комплекса «Позитив»','1474536808.jpg','<p>Capital Group в партнерстве с «Управлением экспериментальной застройки микрорайонов», входящим в девелоперский дивизион городского инжинирингового холдинга «Мосинжпроект», приступили к строительству жилого комплекса комфорт-класса «Позитив» в районе Румянцево Новой Москвы. Генеральным подрядчиком строительства выступила компания  ГВСУ «Центр». Инвестиции в строительство объекта составят 5,7 млрд. рублей.</p><p><br></p><p>\r\n</p><p>\r\nНа территории 5,87 гектаров появится 6 домов переменной этажности – от 17 до 22 этажей – общей площадью 109 тыс. кв. метров. В них предусмотрено 1868 квартир, общая жилая площадь которых составит 89,6 тыс. кв. метров: 1096 однокомнатных, 572 двухкомнатных и 200 трехкомнатных. Первые этажи комплекса площадью 4,4 тыс. кв. метров отведены под сопутствующую инфраструктуру – от коммерции в формате «магазин у дома» до отделений банков. Кроме того, в составе комплекса появится 5-этажный паркинг площадью 16,7 тыс. квадратных метров на 499 машиномест.</p><p><br></p><p>\r\n</p><p>\r\n«ЖК «Позитив» отвечает стандартам новой градостроительной политики Правительства Москвы, – рассказал заместитель генерального директора по девелопменту АО «Мосинжпроект», генеральный директор АО «УЭЗ» Альберт Суниев. – Здесь будет реализован принцип квартальной застройки с дворами свободными от автомобилей, с общественными пространствами на первых этажах и т.п. Важно, что комплекс обеспечен транспортной инфраструктурой: он находится вблизи станций метрополитена «Румянцево» и «Саларьево», недалеко от модернизированной транспортной развязки Киевского шоссе с МКАД».</p><p><br></p><p>\r\n</p><p>\r\n«В строительстве комплекса будет применена инновационная серия домов ДОММОС, – рассказал коммерческий директор Capital Group Алексей Белоусов. - Вентилируемые фасады домов будут оборудованы нишами для кондиционеров и облицованы клинкерной плиткой немецкой фирмы «ABC-Keramik». Применение высокотехнологичной серии ДОММОС позволит оптимизировать сроки строительства».</p><p><br></p><p>\r\n</p><p>\r\nПервая очередь комплекса планируется к сдаче в июле 2017 года</p>','2016-09-12 08:00:00','2016-06-15 10:11:32','2016-09-27 05:49:46'),(16,1,'Старт  продаж  квартир в ЖК комфорт-класса «Позитив»','1474900147.jpg','В жилом комплексе «Позитив», расположенном в 3-х км от МКАД рядом с метро Румянцево (съезд с Киевского шоссе на Солнцево) стартовали продажи квартир комфорт-класса. По итогам конкурса право продажи квартир получили «Est-a-Tet», «БЕСТ-Новострой», «Мосреалстрой», «ГВСУ-Риэлти».\r\n«Мы очень тщательно подходили к выбору брокеров на этот проект, - отметил Алексей Белоусов, коммерческий директор Capital Group. - Помимо опыта продаж объектов комфорт-класса, обязательным условием ни отборе была возможность предоставления с их стороны качественной юридической экспертизы пи заключении каждого договора, так как мы гарантируем будущим жителям комплекса полную юридическую и финансовую чистоту сделки, что очень важно для человека, который вкладывает в покупку строящегося жилья все свои сбережения».\r\n','2016-09-12 11:50:00','2016-09-26 12:10:05','2016-09-26 14:29:07'),(17,1,'Скидки и рассрочки для покупателей квартир в ЖК «Позитив»','1474900056.jpg','Компания Capital Group специально для покупателей квартир в ЖК «Позитив» разработала систему рассрочек платежей, которая предусматривает большой диапазон скидок. Рассчитать персональную скидку покупатель сможет в автоматизированной системе, которая есть у брокеров  ЖК «Позитив». Система предусматривает все возможные периоды оплаты с рассрочкой на год и полгода. Покупатель сам решает, в какой период и какие суммы ему выгоднее платить. \r\nВ зависимости от этого система выдает скидку.\r\n\r\nМаксимально предусмотренная скидка  - 3% от стоимости квартиры при стопроцентной оплате. Рассрочка на полгода при первоначальном взносе 30% предоставляется бесплатно. \r\n','2016-09-16 12:13:00','2016-09-26 12:13:34','2016-09-26 14:27:36'),(18,2,'ЖК «Позитив» получил аккредитацию в банке «Открытие»','1474899899.jpg','С 19 сентября 2016 года покупателям квартир ЖК «Позитив» доступны ипотечные кредиты в банке «Открытие». Банк предлагает кредиты по двум программам. Программа с господдержкой предусматривает ставку от 11,95 % при первоначальном взносе от 30 %. Кредит выдается на срок от 5 до 30 лет.\r\nПо программе «Ипотека-Строящееся жилье» Банк «Открытие» предлагает кредит со ставкой от 13,5 %.\r\nРассчитать кредит можно обратившись к брокерам ЖК «Позитив».\r\n\r\nБанк «Открытие» — крупнейший частный банк в России и четвертый по размеру активов среди всех российских банковских групп\r\nУсловия получения государственной поддержки при ипотечном кредитовании можно узнать на сайте АИЖК <a href=\"http://дом.рф/mortgage/products/prod_gosipoteka/\" target=\"_blank\"><font color=\"#085294\">http://дом.рф/mortgage/products/prod_gosipoteka/</font></a>','2016-09-19 12:14:00','2016-09-26 12:15:49','2016-09-27 05:47:40'),(19,2,'ЖК «Позитив» получил аккредитацию в «Транскапиталбанке»','1474899502.png','<p>С 23 сентября 2016 года покупатели квартир в ЖК «Позитив» могут воспользоваться ипотечными кредитами в «Транскапиталбанке». &nbsp;Ипотека с господдержкой доступна от 10,9%  при первоначальном взносе 20% на срок от 3 до 25 лет.\r\nПодробности на сайте банка <a href=\"http://www.tkbbank.ru/private/credits/mortgage/support/\" target=\"_blank\"><font color=\"#085294\">http://www.tkbbank.ru/private/credits/mortgage/support/</font></a>\r\nТранскапиталбанк  в 2015 году вошел  в топ-10 банков по объему ипотечного кредитования\r\nУсловия получения государственной поддержки при ипотечном кредитовании можно узнать на сайте АИЖК <a href=\"http://xn--d1aqf.xn--p1ai/mortgage/products/prod_gosipoteka/\" target=\"_blank\"><font color=\"#085294\">http://дом.рф/mortgage/products/prod_gosipoteka/</font></a></p>','2016-09-23 12:19:00','2016-09-26 12:20:19','2016-09-27 05:57:40'),(21,1,'ВТБ 24 даст ипотеку покупателям в ЖК «Позитив»','1475871526.png','<p><span style=\"border: none;\">ЖК «Позитив» аккредитован для ипотечных продаж в банке ВТБ 24. С\r\nсегодняшнего дня п</span>окупателям квартир в ЖК\r\n«Позитив» доступны ипотечные кредиты «с <a href=\"http://www.vtb24.ru/mortgage/state\">господдержкой</a>» на срок до 30 лет.\r\n</p><p><br></p><p>По этой программе банк ВТБ 24 фиксирует процентную ставку в размере 11.9%\r\nгодовых на весь срок кредита. Минимальный п<span style=\"border: none;\">ервоначальный взнос\r\nсоставляет 20% от стоимости квартиры.<o:p></o:p></span></p><p><span style=\"border: none;\">Рассчитать условия кредита можно обратившись к брокерам ЖК «Позитив».</span></p><p><span style=\"border: none;\"><o:p></o:p></span></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:PixelsPerInch>96</o:PixelsPerInch>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves></w:TrackMoves>\r\n  <w:TrackFormatting></w:TrackFormatting>\r\n  <w:PunctuationKerning></w:PunctuationKerning>\r\n  <w:ValidateAgainstSchemas></w:ValidateAgainstSchemas>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF></w:DoNotPromoteQF>\r\n  <w:LidThemeOther>RU</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables></w:BreakWrappedTables>\r\n   <w:SnapToGridInCell></w:SnapToGridInCell>\r\n   <w:WrapTextWithPunct></w:WrapTextWithPunct>\r\n   <w:UseAsianBreakRules></w:UseAsianBreakRules>\r\n   <w:DontGrowAutofit></w:DontGrowAutofit>\r\n   <w:SplitPgBreakAndParaMark></w:SplitPgBreakAndParaMark>\r\n   <w:EnableOpenTypeKerning></w:EnableOpenTyp