iority=\"47\" Name=\"List Table 2 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"48\" Name=\"List Table 3 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Mention\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Smart Hyperlink\"/>\r\n </w:LatentStyles>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\ntable.MsoNormalTable\r\n	{mso-style-name:\"Обычная таблица\";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:\"\";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin:0cm;\r\n	mso-para-margin-bottom:.0001pt;\r\n	mso-pagination:widow-orphan;\r\n	font-size:10.0pt;\r\n	font-family:Calibri;}\r\n</style>\r\n<![endif]-->\r\n\r\n\r\n\r\n<!--StartFragment-->\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--EndFragment--></p><p class=\"MsoNormal\"><span style=\"line-height: 115%;\">Жилой комплекс расположен на\r\nтерритории 5,87 гектаров и состоит из 6 новейших панельных домов «ДОММОС»\r\nпроизводства Холдинговой компании «ГВСУ «Центр» переменной этажности – от 17 до\r\n22 этажей – общей площадью 109 тыс. кв. метров. В них предусмотрено 1868 квартир,\r\nобщая жилая площадь которых составит 89,6 тыс. кв. метров: 1096 однокомнатных,\r\n572 двухкомнатных и 200 трехкомнатных. Первые этажи комплекса площадью 4,4 тыс.\r\nкв. метров отведены под сопутствующую инфраструктуру – от коммерции в формате\r\n«магазин у дома» до отделений банков. Кроме того, в составе комплекса появится\r\n5-этажный паркинг площадью 16,7 тыс. квадратных метров на 499 машиномест.<font face=\"Times New Roman\" size=\"3\"><o:p></o:p></font></span></p>','2016-12-05 06:12:00','2016-12-05 10:18:20','2016-12-05 10:19:13'),(30,1,'В ЖК «Позитив» можно купить квартиру без первоначального взноса по ипотеке','1481287563.jpg','<p class=\"MsoNormal\"><span style=\"line-height: 107%;\">С 9 декабря 2016 года ЖК\r\n«Позитив» аккредитован в Металлинвестбанке по программе ипотечного\r\nкредитования. Среди программ банка для покупателей предусмотрена ипотека без первоначального\r\nвзноса, в данном случае ставка по кредиту составит 14%. Программа будет\r\nдействовать до 31.05.2017<o:p></o:p></span></p><p class=\"MsoNormal\"><span style=\"line-height: 107%;\">До 31 декабря 2016 года будущие\r\nжильцы ЖК «Позитив» могут воспользоваться ипотечными программами «Ипотека с\r\nгосподдержкой», первоначальный взнос по которой составляет от 20% (ставка по\r\nкредиту - 10,9%) и «12,5 надо брать», первоначальный взнос по которой\r\nсоставляет от 10%, а ставка по такому кредиту - 12,25%.<o:p></o:p></span></p><p style=\"margin: 0cm 0cm 12pt;\">Рассчитать условия кредита можно обратившись к\r\nброкерам ЖК «Позитив».<o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG/>\r\n  <o:PixelsPerInch>96</o:PixelsPerInch>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves/>\r\n  <w:TrackFormatting/>\r\n  <w:PunctuationKerning/>\r\n  <w:ValidateAgainstSchemas/>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF/>\r\n  <w:LidThemeOther>RU</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-N