ty=\"48\" Name=\"List Table 3 Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"46\"\r\n   Name=\"List Table 1 Light Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"47\" Name=\"List Table 2 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"48\" Name=\"List Table 3 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Mention\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Smart Hyperlink\"/>\r\n </w:LatentStyles>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\ntable.MsoNormalTable\r\n	{mso-style-name:\"Обычная таблица\";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:\"\";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin:0cm;\r\n	mso-para-margin-bottom:.0001pt;\r\n	mso-pagination:widow-orphan;\r\n	font-size:10.0pt;\r\n	font-family:Calibri;}\r\n</style>\r\n<![endif]-->\r\n\r\n\r\n\r\n<!--StartFragment-->\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<span style=\"line-height: 107%;\">ПАО\r\nАКБ «Металлинвестбанк»</span><span style=\"line-height: 107%;\"> успешно работает на\r\nрынке с 1993 года. По данным крупнейших независимых информационно-аналитических\r\nагентств ПАО АКБ «Металлинвестбанк» входит в ТОП-100 крупнейших российских\r\nбанков. ПАО АКБ «Металлинвестбанк» включен в реестр банков, входящих в систему\r\nобязательного страхования вкладов физических лиц, обладает всеми видами\r\nлицензий, необходимыми для осуществления банковских операций, является членом\r\nММВБ, РТС, НВА, НАУФОР, Московской торгово-промышленной палаты и других\r\nассоциаций, и объединений банковского рынка, а также ассоциированным членом\r\nмеждународной платежной системы VISA International и Master Card. </span><!--EndFragment-->    <br></p>','2016-12-09 12:40:00','2016-12-09 12:45:20','2016-12-09 12:46:03'),(31,1,'ЖК «Позитив» аккредитован по ипотечной программе  в СургутнефтегазБанке','1481643436.png','<p>ЖК «Позитив» аккредитован для ипотечных продаж в банке «СургутнефтегазБанк».  Будущим владельцам квартир в ЖК \"Позитив\" банк предлагает ипотечные кредиты по двум программам. Программа «Ипотека с господдержкой», действующая до конца 2016 года,  предусматривает ставку от 10,5% при первоначальном взносе от 20 %. Кредит выдается сроком до 30 лет на максимальную сумму 8 млн. руб. <br>По стандартной программе банк «СургутнефтегазБанк» предлагает кредит со ставкой от 10,9% и первоначальным взносом от 10%.<br><br>Рассчитать кредит можно обратившись к брокерам в офисе продаж ЖК «Позитив». <br><br>Банк «СургутнефтегазБанк» — один из крупнейших региональных банков РФ.  Банк имеет филиалы в Москве, Тюмени, Киришах и более 20 дополнительных офисов в Сургуте, Нефтеюганске, Ханты-Мансийске, Пскове, а также в Сургутском и Нефтеюганском районах.<br></p>','2016-12-13 15:33:00','2016-12-13 15:36:24','2016-12-13 15:37:17'),(32,1,'13 российских банков предлагают ипотеку покупателям ЖК «Позитив»','1482314785.jpg','<div>По состоянию на 20 декабря 2016 года 13 российских банков аккредитовали ЖК «Позитив» по программе ипотечного кредитования. </div><div>В том числе: «ВТБ 24», «ВТБ Банк Москвы», Банк «ДельтаКредит», «Банк Открытие», «Газпромбанк», «СургетнефетегазБанк», «ГЛОБЭКСБАНК», «CМП Банк», «Возрождение», «Промсвязьбанк», «Металлинвестбанк», «Уралсиб», «Транскапиталбанк».</div><div><br></div><div><br></div><div>Программы предусматривают различные условия для заемщиков, ознакомиться с которыми можно в разделе <a href=\"http://www.дом-позитив.рф/ipoteka.html\"><u><b>«Ипотека»</b></u></a></div><div><br></div><div>Покупатели, которые претендуют на ипотечные программы с господдержкой, до конца 2016 года могут успеть воспользоваться этой программой в «ВТБ 24», «ВТБ Банк Москвы», «Уралсиб», «Транскапиталбанк», «Банк Открытие», «Газпромбанк», «СургетнефетегазБанк», Банк «ДельтаКредит» «ГЛОБЭКСБАНК», «Металлинвестбанк».</div>','2016-12-21 10:05:00','2016-12-21 10:06:26','2016-12-21 13:15:30'),(33,1,'«Сбербанк» аккредитовал  ЖК «Позитив»','1482503493.png','<p class=\"MsoNormal\"><span style=\"line-height: 107%;\">С 22 декабря 2016\r\nгода ЖК «Позитив» аккредитован в «Сбербанке» по программе ипотечного\r\nкредитования. </span><span style=\"line-height: 107%;\">В рамках программы «Приобретение строящегося жилья»\r\nпокупателям предоставляется кредит от 300 000 рублей со ставкой от 11,0%\r\nгодовых и 20-процентным первоначальным взносом. Кредит может быть предоставлен\r\nбез подтверждения дохода и занятости. Максимальный возраст заемщика на момент\r\nисполнения обязательств по</span><span style=\"line-height: 107%;\"> </span><span style=\"line-height: 107%;\">кредитному договору <span style=\"mso-spacerun:yes\"> </span>должен составлять 75 лет. <o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin-bottom: 16.8pt; line-height: 16.1pt; background-position: initial initial; background-repeat: initial initial;\"><span style=\"display: none;\">Процентные ставки действуют в рамках Акции с 01.12.2016 по 28.02.2017<o:p></o:p></span></p><p class=\"MsoNormal\"><span style=\"line-height: 107%;\">В целях упрощения\r\nполучения кредитов на покупку квартир в ЖК «Позитив» «Сбербанк» предусмотрел\r\nпрограмму «ипотека по двум документам» (ставка по кредиту от 11,25%,\r\nпервоначальный взнос 50%), в рамках которой помимо паспорта заемщик может\r\nпредоставить один из следующих документов - водительское удостоверение, заграничный\r\nпаспорт, удостоверение личности сотрудника федеральных органов власти,<span style=\"mso-spacerun:yes\">  </span>удостоверение личности военнослужащего, военный\r\nбилет или страховое свидетельство обязательного пенсионного страхования.<o:p></o:p></span></p><p class=\"MsoNormal\"><span style=\"line-height: 107%;\">Также для\r\nпокупателей ЖК «Позитив» предусмотрена «Ипотека с государственной поддержкой»</span><span style=\"line-height: 107%;\"> с\r\nмаксимальной суммой по кредиту 8 000 000 рублей,\r\nставкой в 10,9% сроком до 30 лет.<span style=\"mso-spacerun:yes\">  </span>Программа\r\nдействует до 31.12.2016.<o:p></o:p></span></p><p style=\"margin: 0cm 0cm 12pt;\">С <span style=\"mso-spacerun:yes\"> </span>подробными условиями кредитования можно\r\nознакомиться у брокеров ЖК «Позитив» и на сайте «Сбербанка».<o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG/>\r\n  <o:PixelsPerInch>96</o:PixelsPerInch>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves/>\r\n  <w:TrackFormatting/>\r\n  <w:PunctuationKerning/>\r\n  <w:ValidateAgainstSchemas/>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF/>\r\n  <w:LidThemeOther>RU</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables/>\r\n   <w:SnapToGridInCell/>\