riority=\"46\"\r\n   Name=\"List Table 1 Light Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"47\" Name=\"List Table 2 Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"48\" Name=\"List Table 3 Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"46\"\r\n   Name=\"List Table 1 Light Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"47\" Name=\"List Table 2 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"48\" Name=\"List Table 3 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Mention\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Smart Hyperlink\"/>\r\n </w:LatentStyles>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\ntable.MsoNormalTable\r\n	{mso-style-name:\"Обычная таблица\";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:\"\";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin:0cm;\r\n	mso-para-margin-bottom:.0001pt;\r\n	mso-pagination:widow-orphan;\r\n	font-size:10.0pt;\r\n	font-family:\"Times New Roman\";}\r\n</style>\r\n<![endif]-->\r\n\r\n\r\n\r\n<!--StartFragment-->\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--EndFragment--></p><p><span style=\"border: none;\"><br></span></p><p><span style=\"border: none;\">Банк «Райффайзенбанк» — представлен в России с 1996 года и оказывает\r\nполный спектр услуг частным и корпоративным клиентам, резидентам и\r\nнерезидентам, в рублях и иностранной валюте. Надзор за деятельностью\r\nРайффайзенбанка осуществляет Департамент надзора за системно значимыми кредитными\r\nорганизациями Банка России.<font color=\"#000000\" size=\"4\"><o:p></o:p></font></span></p>','2017-01-20 15:11:00','2017-01-20 15:11:32','2017-01-20 15:14:59'),(35,1,'В ЖК «Позитив» завершен монтаж первого дома','1491299102.jpg','<p class=\"MsoNormal\">В жилом комплексе «Позитив» завершен монтаж первого дома. Это корпус №4 первой очереди строительства, который представляет собой 16-этажный четырёхсекционный панельный дом новой серии «ДОММОС». <o:p></o:p></p><p class=\"MsoNormal\"><o:p> </o:p></p><p class=\"MsoNormal\">Строительство первой и второй очереди ЖК «Позитив» идет по графику. Дома первой очереди планируется сдать в июле 2017 года. Сейчас в корпусе №5 первой очереди уже монтируется 4-й этаж, а в 3 и 6 корпусах второй очереди строители завершили возведение цоколя. Теперь там ведутся монолитные работы по строительству первого этажа. Уже в первой половине апреля на этих объектах планируется начать монтаж панельных секций.<o:p></o:p></p><p class=\"MsoNormal\"><o:p> </o:p></p><p class=\"MsoNormal\">«Мы довольны темпами строительства, но предстоит еще многое сделать. Важно, что выполняется план и соблюдаются сроки. Это значит, что люди получат свои квартиры вовремя», — <span style=\"mso-spacerun:yes\"> </span>комментирует Алексей Белоусов, коммерческий директор <span lang=\"EN-US\">Capital</span><span lang=\"EN-US\"> </span><span lang=\"EN-US\">Group</span>, девелопера проекта ЖК «Позитив».<o:p></o:p></p><p class=\"MsoNormal\"><o:p> </o:p></p><p class=\"MsoNormal\"><o:p> </o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\"><b>Информация о проекте</b></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\">ЖК «Позитив»<span style=\"mso-spacerun:yes\">  </span>— <span style=\"mso-spacerun:yes\"> </span>яркий жилой комплекс, строительство которого проходит на территории Новой Москвы. Он расположен в 3 км от МКАД, рядом со станциями метро Румянцево и Саларьево. Территория комплекса представляет собой квартальную застройку из шести многоэтажных домов, высотой от 16 до 25 этажей. Дома возводятся по новой системе панельного строения ДОММОС. Ее преимущества – это высокое качество, энергоэффективность, множество вариантов планировочных решений и уход от однообразных элементов наружной панели.<span style=\"mso-spacerun:yes\">  </span>Благодаря концепции «Двор без машин» пространство комплекса превращается в парк с зонами для отдыха, детскими и спортивными площадками. К тому же, с разных сторон комплекс окружают Ульяновский лесопарк и Чоботовский лес, что создает на его территории особый микроклимат. <o:p></o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\">Генеральным подрядчиком строительства выступает компания ГВСУ «Центр».<o:p></o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\">Чтобы получить дополнительную информацию о проекте, посетите наш сайт — дом-позитив.рф <o:p></o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\"><o:p> </o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\"><o:p> </o:p></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\"><b>Capital Group</b></p><p class=\"MsoNormal\" style=\"margin-top: 6pt;\">Capital\r\nGroup - одна из старейших российских девелоперских компаний, на рынке с 1993 года. Специализация - комплексное развитие девелоперских проектов.<span style=\"mso-spacerun:yes\">  </span>В портфеле -7,8 млн кв. м реализованных, строящихся и проектируемых объектов, из них 3,3 млн кв. м - в активной фазе строительства. Capital Group специализируется на строительстве многофункциональных комплексов, жилой и коммерческой недвижимости. Помимо традиционных премиального и бизнес-сегментов, с 2009 года развивает масштабные (более миллиона квадратных метров) жилые проекты комфорт-класса.<o:p></o:p></p><p class=\"MsoNormal\" style=\"margin-bottom:10.0pt;mso-outline-level:1\"><o:p> </o:p></p>','2017-04-04 09:35:00','2017-04-04 09:36:04','2017-04-04 09:45:03'),(36,1,'ЖК «Позитив» открывает офис продаж','','<p class=\"MsoNormal\">21 марта в жилом комплексе\r\n«Позитив» открылся новый офис продаж. Клиенты смогут получить консультацию по\r\nповоду покупки квартиры лично у менеджера, приехав по адресу: г. Москва,\r\nпоселение Московский, вблизи д. Румянцево, уч. 3/2. Офис работает с 9 до 21 в\r\nбудни и с 9 до 19 — в выходные.<o:p></o:p></p><p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p><p class=\"MsoNormal\">Специалисты ЖК «Позитив»\r\nготовы предоставить всю необходимую информацию о сроках строительства,\r\nвариантах планировок и условиях приобретения жилья, а также помогут рассчитать\r\nнаиболее удачный вариант покупки квартиры. А чтобы покупатели уже сейчас могли\r\nувидеть, как будет выглядеть комплекс после завершения строительства, в офисе\r\nпредставлен его архитектурный макет.</p>','2017-03-28 09:53:00','2017-04-04 09:54:35','2017-04-04 09:55:13'),(37,1,'В ЖК «Позитив» стартовали продажи новых корпусов','','\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG></o:AllowPNG>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves></w:TrackMoves>\r\n  <w:TrackFormatting></w:TrackFormatting>\r\n  <w:PunctuationKerning></w:PunctuationKerning>\r\n  <w:ValidateAgainstSchemas></w:ValidateAgainstSchemas>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotP