1:53','2017-07-21 09:03:43'),(40,1,'В ЖК «Позитив» в Новой Москве начали монтаж корпусов второй очереди','','<p class=\"MsoNormalCxSpFirst\" style=\"margin-top: 12pt; line-height: normal;\">Девелоперская компания <span lang=\"EN-US\">Capital</span><span lang=\"EN-US\"> </span><span lang=\"EN-US\">Group</span> приступила к монтажу третьего и\r\nшестого корпусов второй очереди жилого комплекса «Позитив» в Новой Москве.</p><p class=\"MsoNormalCxSpFirst\" style=\"margin-top: 12pt; line-height: normal;\">Фундаментные работы в этих домах уже завершены, сделаны\r\nцоколь и входные системы. В третьем корпусе строители приступили к оборудованию\r\nмонолитных конструкций первого этажа, а шестой корпус возведен до уровня второго\r\nэтажа. Закончить монтаж панельных секций и приступить к фасадным работам на\r\nэтих объектах планируется в <span lang=\"EN-US\">III</span><span lang=\"EN-US\"> </span>квартале 2017 года.</p><p class=\"MsoNormalCxSpFirst\" style=\"margin-top: 12pt; line-height: normal;\">При возведении корпусов жилого комплекса «Позитив»\r\nиспользуются современные роботизированные технологии и универсальные панельные\r\nконструкции. Система крупнопанельных домов ДОММОС определяет скорость\r\nстроительства и выразительный архитектурный облик зданий.</p><p class=\"MsoNormalCxSpFirst\" style=\"margin-top: 12pt; line-height: normal;\">«Мы завершили монолитные работы в четвертом и пятом домах\r\nпервой очереди и теперь приступаем к монтажу следующих по плану зданий, —\r\nкомментирует Алексей Белоусов, коммерческий директор <span lang=\"EN-US\">Capital</span><span lang=\"EN-US\"> </span><span lang=\"EN-US\">Group</span>, — квартиры в этих корпусах\r\nпродаются с апреля, и динамика продаж на объекте не уступает темпам\r\nстроительства. Сдать в эксплуатацию дома второй очереди мы рассчитываем уже в <span lang=\"EN-US\">IV</span><span lang=\"EN-US\"> </span>квартале 2017 года».&nbsp;</p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG/>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves/>\r\n  <w:TrackFormatting/>\r\n  <w:PunctuationKerning/>\r\n  <w:ValidateAgainstSchemas/>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF/>\r\n  <w:LidThemeOther>RU</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables/>\r\n   <w:SnapToGridInCell/>\r\n   <w:WrapTextWithPunct/>\r\n   <w:UseAsianBreakRules/>\r\n   <w:DontGrowAutofit/>\r\n   <w:SplitPgBreakAndParaMark/>\r\n   <w:EnableOpenTypeKerning/>\r\n   <w:DontFlipMirrorIndents/>\r\n   <w:OverrideTableStyleHps/>\r\n  </w:Compatibility>\r\n  <m:mathPr>\r\n   <m:mathFont m:val=\"Cambria Math\"/>\r\n   <m:brkBin m:val=\"before\"/>\r\n   <m:brkBinSub m:val=\"&#45;-\"/>\r\n   <m:smallFrac m:val=\"off\"/>\r\n   <m:dispDef/>\r\n   <m:lMargin m:val=\"0\"/>\r\n   <m:rMargin m:val=\"0\"/>\r\n   <m:defJc m:val=\"centerGroup\"/>\r\n   <m:wrapIndent m:val=\"1440\"/>\r\n   <m:intLim m:val=\"subSup\"/>\r\n   <m:naryLim m:val=\"undOvr\"/>\r\n  </m:mathPr></w:WordDocument>\r\n</xml><![endif]--><!--[if gte mso 9]><xml>\r\n <w:LatentStyles DefLockedState=\"false\" DefUnhideWhenUsed=\"false\"\r\n  DefSemiHidden=\"false\" DefQFormat=\"false\" DefPriority=\"99\"\r\n  LatentStyleCount=\"382\">\r\n  <w:LsdException Locked=\"false\" Priority=\"0\" QFormat=\"true\" Name=\"Normal\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" QFormat=\"true\" Name=\"heading 1\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 2\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\