e>\r\n /* Style Definitions */\r\ntable.MsoNormalTable\r\n	{mso-style-name:\"Обычная таблица\";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:\"\";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin-top:0cm;\r\n	mso-para-margin-right:0cm;\r\n	mso-para-margin-bottom:10.0pt;\r\n	mso-para-margin-left:0cm;\r\n	line-height:115%;\r\n	mso-pagination:widow-orphan;\r\n	font-size:11.0pt;\r\n	font-family:Calibri;\r\n	mso-ascii-font-family:Calibri;\r\n	mso-ascii-theme-font:minor-latin;\r\n	mso-hansi-font-family:Calibri;\r\n	mso-hansi-theme-font:minor-latin;\r\n	mso-fareast-language:EN-US;}\r\n</style>\r\n<![endif]-->\r\n\r\n\r\n\r\n<!--StartFragment-->\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--EndFragment--></p><p class=\"MsoNormalCxSpMiddle\" style=\"margin-top: 12pt; line-height: normal;\">Минимальная стоимость квартиры в жилом комплексе «Позитив» —\r\n3,8 млн. рублей. <font face=\"Arial\" size=\"3\"><o:p></o:p></font></p>','2017-06-01 09:01:00','2017-07-21 09:03:18','2017-07-21 09:03:18'),(41,1,'Capital Group реализовал новую для рынка недвижимости комбинированную схему продаж — рассрочка плюс скидка — на примере ЖК «Позитив»','','<p class=\"MsoNormal\">Гибкая схема оплаты квартиры в рассрочку предусматривает\r\nполучение покупателем скидки до 3%: чем раньше будет оплачена полная стоимость\r\nквартиры, тем больше размер дисконта, предоставляемый покупателю.</p><p class=\"MsoNormal\"><o:p></o:p></p><p class=\"MsoNormal\"><br></p><p class=\"MsoNormal\">Новая для рынка концепция отсроченного платежа,\r\nреализованная девелоперской компанией Capital Group на их первом объекте\r\nкомфорт класса в Новой Москве — жилом комплексе «Позитив», предполагает\r\nкомфортные сроки выплат по рассрочке и возможность получить скидку до\r\n232&nbsp;000 рублей в случае раннего закрытия сделки.</p><p class=\"MsoNormal\"><br></p><p class=\"MsoNormal\">Схема получения скидки прозрачна: минимальный первоначальный\r\nвзнос — 30%. Затем полная стоимость квартиры разделяется на шесть равных\r\nплатежей. Если покупатель выплачивает необходимую сумму за 6 месяцев, то\r\nстоимость квартиры остается прежней, если раньше, к примеру, за 4 или 5\r\nмесяцев, то получает скидку. Размер скидки пересчитывается автоматически и\r\nнапрямую зависит от того, как быстро закрывается сделка.</p><p class=\"MsoNormal\"><br></p><p class=\"MsoNormal\"><o:p></o:p></p><p class=\"MsoNormal\">Таким образом, по рассрочке реальным становится получить\r\nскидку в 2,9% – 2,8%. При минимальной стоимости однокомнатной квартиры в ЖК\r\n«Позитив» в 3,8 млн. рублей, максимальная скидка составит 110&nbsp;000 рублей в\r\nслучае оплаты квартиры в течение 2 месяцев. В случае, если вы приобретаете\r\nтрехкомнатную квартиру стоимостью до 8 млн. рублей, то максимальный размер\r\nскидки — 232&nbsp;000 рублей.</p><p class=\"MsoNormal\"><o:p></o:p></p><p class=\"MsoNormal\"><br></p><p class=\"MsoNormal\">При этом стопроцентная оплата квартиры в течение одного\r\nмесяца обеспечивает максимальную скидку – за быстрые деньги девелопер готов\r\nсделать дисконт 3 %. Покупатель, таким образом, может сам рассчитать удобные\r\nсроки выплат и в зависимости от этого ориентироваться на определенную скидку.<o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG/>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]-->\r\n\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves/>\r\n  <w:TrackFormatting/>\r\n  <w:PunctuationKerning/>\r\n  <w:ValidateAgainstSchemas/>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF/>\r\n  <w:LidThemeOther>RU</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables/>\r\n   <w:SnapToGridInCell/>\r\n   <w:WrapTextWithPunct/>\r\n   <w:UseAsianBreakRules/>\r\n   <w:DontGrowAutofit/>\r\n   <w:SplitPgBreakAndParaMark/>\r\n   <w:EnableOpenTypeKerning/>\r\n   <w:DontFlipMirrorIndents/>\r\n   <w:OverrideTableStyleHps/>\r\n  </w:Compatibility>\r\n  <m:mathPr>\r\n   <m:mathFont m:val=\"Cambria Math\"/>\r\n   <m:brkBin m:val=\"before\"/>\r\n   <m:brkBinSub m:val=\"&#45;-\"/>\r\n   <m:smallFrac m:val=\"off\"/>\r\n   <m:dispDef/>\r\n   <m:lMargin m:val=\"0\"/>\r\n   <m:rMargin m:val=\"0\"/>\r\n   <m:defJc m:val=\"centerGroup\"/>\r\n   <m:wrapIndent m:val=\"1440\"/>\r\n   <m:intLim m:val=\"subSup\"/>\r\n   <m:naryLim m:val=\"undOvr\"/>\r\n  </m:mathPr></w:WordDocument>\r\n</xml><![endif]--><!--[if gte mso 9]><xml>\r\n <w:LatentStyles DefLockedState=\"false\" DefUnhideWhenUsed=\"false\"\r\n  DefSemiHidden=\"false\" DefQFormat=\"false\" DefPriority=\"99\"\r\n  LatentStyleCount=\"382\">\r\n  <w:LsdException Locked=\"false\" Priority=\"0\" QFormat=\"true\" Name=\"Normal\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" QFormat=\"true\" Name=\"heading 1\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 2\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 3\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 4\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   UnhideWhenUsed=\"true\" QFormat=\"true\" Name=\"heading 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"9\" SemiHidden=\"true\"\r\n   Unhide